// bitset
bitset<N> dp;
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i], a[i] %= m;
	fa(i, 1, n) {
      	// (dp << a[i]) 表示余数直接加上 a[i]
		// (dp >> (m - a[i])) 表示余数加上 a[i] 后大于等于 m 了，绕回到前面
		dp |= (dp << a[i]) | (dp >> (m - a[i]));
		dp[a[i]] = 1; // 为了不初始化 dp[0] = 1，在这单独给出
	}
	if (dp[0])cout << "YES" << endl;
	else cout << "NO" << endl;
	return;
}

// 鸽巢原理
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i], a[i] %= m;
	if (n >= m) {
		cout << "YES" << endl;
		return;
	}
	var dp = Vec2<int>(n + 1, m + 1);
	fa(i, 1, n) {
		fa(j, 0, m - 1) {
			dp[i][(j + a[i]) % m] |= dp[i - 1][j];
			dp[i][j] |= dp[i - 1][j];
		}
		dp[i][a[i]] = 1;
	}
	if (dp[n][0])cout << "YES" << endl;
	else cout << "NO" << endl;
	return;
}
